async function main() {
  console.log("🌱 Seeding database with startup postmortems...\n");

  // Clear existing data
  await prisma.startup.deleteMany();
  await prisma.user.deleteMany();

  // Create a system user for all seeded entries
  const systemUser = await prisma.user.create({
    data: {
      email: "founders@founderautopsy.com",
      password: "$2b$10$seededSystemUserNotForLogin",
    },
  });

  console.log(`✅ Created system user: ${systemUser.email}\n`);

  for (const startup of startups) {
    const created = await prisma.startup.create({
      data: {
        ...startup,
        submittedBy: systemUser.id,
      },
    });
    console.log(`✅ ${created.name} (${created.foundedYear}–${created.closedYear}) — ${created.industry}`);
  }

  console.log(`\n🎉 Seeding complete! ${startups.length} startup postmortems loaded.\n`);
  console.log("Startups by failure category:");
  const tagCounts: Record<string, number> = {};
  for (const s of startups) {
    const tags = JSON.parse(s.aiTags) as string[];
    for (const tag of tags) {
      tagCounts[tag] = (tagCounts[tag] || 0) + 1;
    }
  }
  for (const [tag, count] of Object.entries(tagCounts).sort((a, b) => b[1] - a[1])) {
    console.log(`  ${tag}: ${count}`);
  }
}

main()
  .catch((e) => {
    console.error(e);
    process.exit(1);
  })
  .finally(async () => {
    await prisma.$disconnect();
  });
